Here are the public test cases for feature1_basic_storage:
{
  "description": "Values written under a logical key can be read back from the same cache namespace, and each successful write reports that the value was accepted.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "read",
            "key": "foo"
          }
        ]
      },
      "expected_output": "saved=true\nfoo=bar\n"
    }
  ]
}

Here are the public test cases for feature2_removal_and_absence:
{
  "description": "A missing key reads as an undefined value; removing an existing key reports success and makes later reads undefined, while removing a missing key reports no removal.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "steps": [
          {
            "action": "read",
            "key": "foo",
            "label": "before"
          },
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "remove",
            "key": "foo",
            "label": "removed_existing"
          },
          {
            "action": "read",
            "key": "foo",
            "label": "after"
          },
          {
            "action": "remove",
            "key": "foo",
            "label": "removed_missing"
          }
        ]
      },
      "expected_output": "before=undefined\nsaved=true\nremoved_existing=true\nafter=undefined\nremoved_missing=false\n"
    }
  ]
}

Here are the public test cases for feature3_clear_all_entries:
{
  "description": "Clearing a cache namespace removes every value in that namespace and reports an undefined result for the clearing operation.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "save",
            "key": "fizz",
            "value": "buzz"
          },
          {
            "action": "clear",
            "label": "clear_result"
          },
          {
            "action": "read",
            "key": "foo"
          },
          {
            "action": "read",
            "key": "fizz"
          }
        ]
      },
      "expected_output": "saved=true\nsaved=true\nclear_result=undefined\nfoo=undefined\nfizz=undefined\n"
    }
  ]
}

Here are the public test cases for feature4_expiration_rules:
{
  "description": "Stored values can expire after a default lifetime, per-entry lifetimes override the default, and an explicit zero lifetime keeps a value from expiring.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "default_lifetime_ms": 100,
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "read",
            "key": "foo",
            "label": "before"
          },
          {
            "action": "advance_time",
            "milliseconds": 150
          },
          {
            "action": "read",
            "key": "foo",
            "label": "after"
          },
          {
            "action": "store_entries",
            "label": "remaining_keys"
          }
        ]
      },
      "expected_output": "saved=true\nbefore=bar\nafter=undefined\nremaining_keys=0\n"
    },
    {
      "input": {
        "namespace": "keyv",
        "default_lifetime_ms": 200,
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "save",
            "key": "fizz",
            "value": "buzz",
            "lifetime_ms": 100
          },
          {
            "action": "save",
            "key": "ping",
            "value": "pong",
            "lifetime_ms": 300
          },
          {
            "action": "read",
            "key": "foo",
            "label": "t0_foo"
          },
          {
            "action": "read",
            "key": "fizz",
            "label": "t0_fizz"
          },
          {
            "action": "read",
            "key": "ping",
            "label": "t0_ping"
          },
          {
            "action": "advance_time",
            "milliseconds": 150
          },
          {
            "action": "read",
            "key": "foo",
            "label": "t150_foo"
          },
          {
            "action": "read",
            "key": "fizz",
            "label": "t150_fizz"
          },
          {
            "action": "read",
            "key": "ping",
            "label": "t150_ping"
          },
          {
            "action": "advance_time",
            "milliseconds": 100
          },
          {
            "action": "read",
            "key": "foo",
            "label": "t250_foo"
          },
          {
            "action": "read",
            "key": "ping",
            "label": "t250_ping"
          },
          {
            "action": "advance_time",
            "milliseconds": 100
          },
          {
            "action": "read",
            "key": "ping",
            "label": "t350_ping"
          }
        ]
      },
      "expected_output": "saved=true\nsaved=true\nsaved=true\nt0_foo=bar\nt0_fizz=buzz\nt0_ping=pong\nt150_foo=bar\nt150_fizz=undefined\nt150_ping=pong\nt250_foo=undefined\nt250_ping=pong\nt350_ping=undefined\n"
    },
    {
      "input": {
        "namespace": "keyv",
        "default_lifetime_ms": 200,
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar",
            "lifetime_ms": 0
          },
          {
            "action": "read",
            "key": "foo",
            "label": "before"
          },
          {
            "action": "advance_time",
            "milliseconds": 250
          },
          {
            "action": "read",
            "key": "foo",
            "label": "after"
          }
        ]
      },
      "expected_output": "saved=true\nbefore=bar\nafter=bar\n"
    }
  ]
}

Here are the public test cases for feature5_namespace_isolation:
{
  "description": "Independent namespaces can use the same logical keys without collisions; removal or clearing in one namespace does not remove values in another namespace.",
  "cases": [
    {
      "input": {
        "shared_store": true,
        "steps": [
          {
            "action": "save",
            "namespace": "alpha",
            "key": "foo",
            "value": "value-alpha"
          },
          {
            "action": "save",
            "namespace": "beta",
            "key": "foo",
            "value": "value-beta"
          },
          {
            "action": "read",
            "namespace": "alpha",
            "key": "foo",
            "label": "alpha_foo"
          },
          {
            "action": "read",
            "namespace": "beta",
            "key": "foo",
            "label": "beta_foo"
          }
        ]
      },
      "expected_output": "saved=true\nsaved=true\nalpha_foo=value-alpha\nbeta_foo=value-beta\n"
    },
    {
      "input": {
        "shared_store": true,
        "steps": [
          {
            "action": "save",
            "namespace": "alpha",
            "key": "foo",
            "value": "value-alpha"
          },
          {
            "action": "save",
            "namespace": "beta",
            "key": "foo",
            "value": "value-beta"
          },
          {
            "action": "remove",
            "namespace": "alpha",
            "key": "foo",
            "label": "removed_alpha"
          },
          {
            "action": "read",
            "namespace": "alpha",
            "key": "foo",
            "label": "alpha_after"
          },
          {
            "action": "read",
            "namespace": "beta",
            "key": "foo",
            "label": "beta_after"
          }
        ]
      },
      "expected_output": "saved=true\nsaved=true\nremoved_alpha=true\nalpha_after=undefined\nbeta_after=value-beta\n"
    },
    {
      "input": {
        "shared_store": true,
        "steps": [
          {
            "action": "save",
            "namespace": "alpha",
            "key": "foo",
            "value": "value-alpha"
          },
          {
            "action": "save",
            "namespace": "alpha",
            "key": "bar",
            "value": "value-alpha"
          },
          {
            "action": "save",
            "namespace": "beta",
            "key": "foo",
            "value": "value-beta"
          },
          {
            "action": "save",
            "namespace": "beta",
            "key": "bar",
            "value": "value-beta"
          },
          {
            "action": "clear",
            "namespace": "alpha",
            "label": "clear_alpha"
          },
          {
            "action": "read",
            "namespace": "alpha",
            "key": "foo",
            "label": "alpha_foo"
          },
          {
            "action": "read",
            "namespace": "alpha",
            "key": "bar",
            "label": "alpha_bar"
          },
          {
            "action": "read",
            "namespace": "beta",
            "key": "foo",
            "label": "beta_foo"
          },
          {
            "action": "read",
            "namespace": "beta",
            "key": "bar",
            "label": "beta_bar"
          }
        ],
        "backend": "temporary_file"
      },
      "expected_output": "saved=true\nsaved=true\nsaved=true\nsaved=true\nclear_alpha=undefined\nalpha_foo=undefined\nalpha_bar=undefined\nbeta_foo=value-beta\nbeta_bar=value-beta\n"
    }
  ]
}

Here are the public test cases for feature6_value_shapes:
{
  "description": "The cache preserves supported value shapes including booleans, nulls, numbers, objects, byte sequences, quoted strings, and large numeric values.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "values": [
          {
            "label": "false_value",
            "key": "false",
            "value": false
          },
          {
            "label": "null_value",
            "key": "null",
            "value": null
          },
          {
            "label": "number_value",
            "key": "number",
            "value": 0
          },
          {
            "label": "object_value",
            "key": "object",
            "value": {
              "fizz": "buzz"
            }
          },
          {
            "label": "bytes_value",
            "key": "bytes",
            "value": {
              "$bytes_base64": "YmFy"
            }
          },
          {
            "label": "object_bytes_value",
            "key": "object_bytes",
            "value": {
              "buff": {
                "$bytes_base64": "YnV6eg=="
              }
            }
          },
          {
            "label": "quote_value",
            "key": "quote",
            "value": "\""
          },
          {
            "label": "large_number_value",
            "key": "large",
            "value": 9223372036854776000
          }
        ]
      },
      "expected_output": "false_value=false\nnull_value=null\nnumber_value=0\nobject_value={\"fizz\":\"buzz\"}\nbytes_value=bytes:YmFy\nobject_bytes_value={\"buff\":\"bytes:YnV6eg==\"}\nquote_value=\"\nlarge_number_value=9223372036854776000\n"
    }
  ]
}

Here are the public test cases for feature7_raw_record_view:
{
  "description": "A caller may request the stored record shape instead of only the value, receiving the saved value together with its expiration metadata.",
  "cases": [
    {
      "input": {
        "namespace": "keyv",
        "steps": [
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "read_record",
            "key": "foo",
            "label": "record"
          }
        ]
      },
      "expected_output": "saved=true\nrecord.value=bar\nrecord.expires=null\n"
