Here are the public test cases for feature9_uri_backed_storage:
{
  "description": "A file-backed storage URI can be used as a cache backend; values can be read after writing and are absent again after the namespace is cleared.",
  "cases": [
    {
      "input": {
        "backend": "temporary_file",
        "namespace": "keyv",
        "steps": [
          {
            "action": "read",
            "key": "foo",
            "label": "initial"
          },
          {
            "action": "save",
            "key": "foo",
            "value": "bar"
          },
          {
            "action": "read",
            "key": "foo",
            "label": "after_write"
          },
          {
            "action": "clear",
            "label": "clear_result"
          },
          {
            "action": "read",
            "key": "foo",
            "label": "after_clear"
          }
        ]
      },
      "expected_output": "initial=undefined\nsaved=true\nafter_write=bar\nclear_result=undefined\nafter_clear=undefined\n"
